public static String solve(String s, long k) {
    int n = s.length();
    long total = 0;
    long[] lens = new long[n];
    for (int i = 0; i < n; i++) {
        char c = s.charAt(i);
        if (c >= 'a' && c <= 'z') {
            total++;
        } else if (c == '*') {
            total = Math.max(0, total - 1);
        } else if (c == '#') {
            total *= 2;
        }
        lens[i] = total;
    }

    if (k >= total) {
        return ".";
    }

    long currentK = k;
    for (int i = n - 1; i >= 0; i--) {
        char c = s.charAt(i);
        long prev = (i > 0) ? lens[i - 1] : 0;

        if (c >= 'a' && c <= 'z') {
            if (currentK == lens[i] - 1) {
                return String.valueOf(c);
            }
        } else if (c == '*') {
            // No change to currentK
        } else if (c == '#') {
            if (prev > 0) {
                if (currentK >= prev) {
                    currentK -= prev;
                }
            }
        } else if (c == '%') {
            if (prev > 0) {
                currentK = prev - 1 - currentK;
            }
        }
    }

    return ".";
}
```

